func (q *Queries) TouchCategorySearchCache(ctx context.Context, arg TouchCategorySearchCacheParams) error {
	_, err := q.db.Exec(ctx, touchCategorySearchCache, arg.NormalizedQuery, arg.LastAccessedAt)
	return err
}

